// Format CRM response into structured output for OpenClaw
const crmData = $input.first().json;

// Handle empty/not-found responses
if (!crmData || (Array.isArray(crmData) && crmData.length === 0)) {
  return [{
    json: {
      success: true,
      found: false,
      contact: null,
      message: 'No contact found matching the search criteria'
    }
  }];
}

const contact = Array.isArray(crmData) ? crmData[0] : crmData;

return [{
  json: {
    success: true,
    found: true,
    contact: {
      id: contact.id || null,
      first_name: contact.first_name || contact.firstName || null,
      last_name: contact.last_name || contact.lastName || null,
      email: contact.email || null,
      phone: contact.phone || null,
      status: contact.status || null,
      created_at: contact.created_at || contact.createdAt || null,
      tags: contact.tags || [],
      custom_fields: contact.custom_fields || {}
    },
    source: 'crm',
    retrieved_at: new Date().toISOString()
  }
}];
